        ("Reverse".to_string(), (1..=size as i32).rev().collect()),
        ("AllSame".to_string(), vec![42; size]),
        ("AlmostSorted".to_string(), {
            let mut seq: Vec<i32> = (1..=size as i32).collect();
            if size > 2 {
                seq.swap(0, size - 1); // Swap first and last
            }
            seq
        }),
    ]
}

